const email = process.env.DEMO_ADMIN_EMAIL || 'admin@taskvault.demo';
const password = process.env.DEMO_ADMIN_PASSWORD || 'password123';
const backend = 'http://backend-service:8080';
const login = await fetch(`${backend}/api/auth/login`, {
  method: 'POST',
  headers: { 'content-type': 'application/json' },
  body: JSON.stringify({ email, password }),
});
if (!login.ok) throw new Error(`login failed: ${login.status}`);
const { token } = await login.json();
const report = await fetch(`${backend}/api/admin/reports/run`, {
  method: 'POST',
  headers: { authorization: `Bearer ${token}` },
});
if (!report.ok) throw new Error(`report trigger failed: ${report.status}`);
console.log(await report.text());

